// src/store/slices/cartSlice.js

import { createSlice } from '@reduxjs/toolkit';

// 1. Хелпер: Получение состояния из LocalStorage
const getInitialState = () => {
  try {
    const persistedCart = localStorage.getItem('cartItems');
    return persistedCart ? JSON.parse(persistedCart) : [];
  } catch (error) {
    console.error("Error loading cart from storage:", error);
    return [];
  }
};

// 2. Хелпер: Сохранение состояния в LocalStorage
const saveState = (state) => {
  localStorage.setItem('cartItems', JSON.stringify(state));
};


const cartSlice = createSlice({
  name: 'cart',
  initialState: {
    items: getInitialState(), // Загружаем из localStorage
  },
  reducers: {
    // 3. Редьюсер: Добавление товара
    addToCart: (state, action) => {
      const { id, title, price, image, discont_price } = action.payload;

      const existingItem = state.items.find(item => item.id === id);

      if (existingItem) {
        existingItem.count += 1;
      } else {
        // Добавляем новый товар в корзину
        const currentPrice = discont_price !== null ? discont_price : price;
        state.items.push({
          id,
          title,
          price: currentPrice, // В корзине храним уже рассчитанную актуальную цену
          originalPrice: price, // Храним исходную цену для отображения скидки
          image,
          count: 1,
        });
      }
      saveState(state.items);
    },

    // 4. Редьюсер: Увеличение количества
    increaseCount: (state, action) => {
      const { id } = action.payload;
      const item = state.items.find(item => item.id === id);
      if (item) {
        item.count += 1;
      }
      saveState(state.items);
    },

    // 5. Редьюсер: Уменьшение количества
    decreaseCount: (state, action) => {
      const { id } = action.payload;
      const item = state.items.find(item => item.id === id);
      if (item && item.count > 1) {
        item.count -= 1;
      }
      saveState(state.items);
    },

    // 6. Редьюсер: Удаление товара
    removeFromCart: (state, action) => {
      const { id } = action.payload;
      state.items = state.items.filter(item => item.id !== id);
      saveState(state.items);
    },

    // 7. Редьюсер: Очистка корзины (после успешного заказа)
    clearCart: (state) => {
      state.items = [];
      saveState(state.items);
    }
  },
});

export const { 
  addToCart, 
  increaseCount, 
  decreaseCount, 
  removeFromCart, 
  clearCart 
} = cartSlice.actions;

export default cartSlice.reducer;
